mapper.select:
SELECT qwi.报价危废明细编号, qwi.报价条目编号, qwi.危废条目编号, hwc.废物类别, hwi.行业来源, hwi.废物代码, qwi.废物名称, qwi.废物形态, qwi.计量单位, qwi.计划转移数量, qwi.是否启用辅助核算, qwi.辅助计量单位, qwi.辅助单位每基础单位数量, qwi.辅助数量, qwi.辅助单价, qwi.付款方, qwi.计价方案, qwi.备注, qwi.创建时间 FROM QUOTATION_WASTE_ITEM qwi LEFT JOIN HAZARDOUS_WASTE_ITEM hwi ON qwi.危废条目编号 = hwi.条目编号 LEFT JOIN HAZARDOUS_WASTE_CATEGORY hwc ON hwi.废物类别编号 = hwc.废物类别编号 WHERE qwi.报价条目编号 IN
#{itemId}
ORDER BY qwi.报价条目编号 ASC, qwi.创建时间 ASC

mapper.delete:
DELETE FROM QUOTATION_WASTE_ITEM
WHERE 报价条目编号 IN

    #{itemId}
